export interface TokenResponse {
  token: string;
  // Add other fields if returned by the auth endpoint, but token is primary
}

export interface Ticket {
  ticketId: number;
  ticketClientCode: string;
  ticketClientName: string;
  priority: string;
  ticketType: string;
  ticketSource: string;
  subject: string;
  status: string;
  created: string;
  updated: string;
  resolved?: string;
  lastUpdatedByEmail?: string;
  requesterEmail?: string;
}

export interface SearchResponse {
  searchResults: Ticket[];
  total: number;
}

export interface HistoryFieldUpdate {
  field: string;
  id: number;
  newValue: string;
  oldValue: string;
}

export interface HistoryComment {
  id: number;
  contentType: string;
  content: string; // HTML string
  workflowChoice?: string;
}

export interface TicketHistoryItem {
  id: number;
  created: string;
  actorId: string;
  actorName?: string; // Often null in JSON, fallback to email if available in context
  source: string; // 'workflow', 'email', etc.
  comment?: HistoryComment;
  fieldUpdates?: HistoryFieldUpdate[];
  ticketId: number;
}

export interface HistoryResponse {
  content: TicketHistoryItem[];
}

export interface FilterParams {
  clientCode: string;
  clientName: string;
  priority: string;
  ticketType: string;
  dateFrom: string;
  dateTo: string;
}

export enum ViewState {
  LOGIN,
  DASHBOARD
}

import { Ticket, SearchResponse, HistoryResponse, FilterParams } from '../types';

const AUTH_URL = 'https://support.amelia.com/AmeliaRest/api/v1/aiops/token/get';
const BASE_REPORTING_URL = 'https://support.amelia.com/api/reporting/export';
const BASE_TICKET_URL = 'https://support.amelia.com/api/tickets';

export class ApiService {
  private static token: string | null = null;

  static setToken(token: string) {
    this.token = token;
  }

  static getToken(): string | null {
    return this.token;
  }

  static async login(username: string, password: string): Promise<string> {
    const response = await fetch(AUTH_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        ameliaUrl: "https://support.amelia.com/Amelia",
        username,
        password
      }),
    });

    if (!response.ok) {
      throw new Error('Authentication failed');
    }

    // The curl example implies the token is returned. 
    // Depending on the actual response (plain string or JSON), we handle it.
    // Based on standard JWT flows, usually it's a JSON object or plain text.
    // We will assume text if JSON parsing fails, or extract from JSON.
    const text = await response.text();
    try {
      const json = JSON.parse(text);
      // Adjust this depending on actual key. 
      // If the curl returns just the token string in body (unlikely for REST but possible):
      return json.token || json; 
    } catch {
      return text;
    }
  }

  static async searchTickets(filters: FilterParams): Promise<SearchResponse> {
    if (!this.token) throw new Error('Not authenticated');

    const queryParts: string[] = [];

    if (filters.clientCode) queryParts.push(`ticketClientCode:${filters.clientCode}`);
    if (filters.clientName) queryParts.push(`ticketClientName:${filters.clientName}`);
    if (filters.priority) queryParts.push(`priority:${filters.priority}`);
    if (filters.ticketType) queryParts.push(`ticketType:${filters.ticketType}`);

    // Date handling
    if (filters.dateFrom && filters.dateTo) {
      // API expects: created:["2025-11-01T00:00:00" TO "2025-12-12T00:00:00.000"]
      const from = `${filters.dateFrom}T00:00:00`;
      const to = `${filters.dateTo}T23:59:59.999`;
      queryParts.push(`created:["${from}" TO "${to}"]`);
    }

    const queryString = queryParts.join(' AND ');
    const encodedQuery = encodeURIComponent(queryString);

    // Defaulting to page 0, size 50 for the UI
    const url = `${BASE_REPORTING_URL}?index=tasks&showTotal=true&page=0&size=50&q=${encodedQuery}`;

    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${this.token}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      throw new Error(`Search failed: ${response.statusText}`);
    }

    return await response.json();
  }

  static async getTicketHistory(ticketId: number): Promise<HistoryResponse> {
    if (!this.token) throw new Error('Not authenticated');

    const url = `${BASE_TICKET_URL}/${ticketId}/history`;

    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${this.token}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch history: ${response.statusText}`);
    }

    return await response.json();
  }
}

import React, { useState } from 'react';
import { ApiService } from '../services/api';
import { Lock, User, Loader2 } from 'lucide-react';

interface LoginFormProps {
  onLoginSuccess: () => void;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLoginSuccess }) => {
  const [username, setUsername] = useState('reporting_api@ipsoft.com');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      const token = await ApiService.login(username, password);
      ApiService.setToken(token);
      onLoginSuccess();
    } catch (err) {
      setError('Invalid credentials or server error.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50">
      <div className="max-w-md w-full bg-white rounded-xl shadow-lg overflow-hidden border border-slate-100">
        <div className="bg-blue-600 p-8 text-center">
          <h1 className="text-3xl font-bold text-white mb-2">Amelia Insights</h1>
          <p className="text-blue-100">Secure Reporting Dashboard</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          {error && (
            <div className="p-4 bg-red-50 border-l-4 border-red-500 text-red-700 text-sm rounded">
              {error}
            </div>
          )}

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">Username</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <User className="h-5 w-5 text-slate-400" />
              </div>
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="block w-full pl-10 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 text-slate-900 sm:text-sm transition-colors"
                placeholder="Enter your username"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">Password</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Lock className="h-5 w-5 text-slate-400" />
              </div>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="block w-full pl-10 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 text-slate-900 sm:text-sm transition-colors"
                placeholder="••••••••"
                required
              />
            </div>
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full flex justify-center items-center py-2.5 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
          >
            {isLoading ? (
              <>
                <Loader2 className="animate-spin -ml-1 mr-2 h-4 w-4" />
                Authenticating...
              </>
            ) : (
              'Sign In'
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default LoginForm;

import React, { useState } from 'react';
import { ApiService } from '../services/api';
import { Ticket, TicketHistoryItem, FilterParams } from '../types';
import { 
  Search, 
  Calendar, 
  Filter, 
  Clock, 
  CheckCircle2, 
  AlertCircle, 
  MessageSquare, 
  ChevronRight,
  ArrowLeft,
  RefreshCw,
  Tag
} from 'lucide-react';

const Dashboard: React.FC = () => {
  // State
  const [filters, setFilters] = useState<FilterParams>({
    clientCode: '',
    clientName: '',
    priority: '',
    ticketType: '',
    dateFrom: new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0], // Last 30 days default
    dateTo: new Date().toISOString().split('T')[0]
  });

  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);
  const [history, setHistory] = useState<TicketHistoryItem[]>([]);

  const [isSearching, setIsSearching] = useState(false);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const [error, setError] = useState('');

  // Handlers
  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setIsSearching(true);
    setError('');
    setSelectedTicket(null); // clear selection on new search

    try {
      const response = await ApiService.searchTickets(filters);
      setTickets(response.searchResults);
    } catch (err) {
      console.error(err);
      setError('Failed to fetch tickets. Please check your filters.');
    } finally {
      setIsSearching(false);
    }
  };

  const handleTicketSelect = async (ticket: Ticket) => {
    setSelectedTicket(ticket);
    setIsLoadingHistory(true);
    try {
      const response = await ApiService.getTicketHistory(ticket.ticketId);
      setHistory(response.content);
    } catch (err) {
      console.error(err);
      // Don't clear ticket selection, just show error in panel
    } finally {
      setIsLoadingHistory(false);
    }
  };

  const handleFilterChange = (key: keyof FilterParams, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  // Helper for Status Colors
  const getStatusColor = (status: string) => {
    switch (status.toUpperCase()) {
      case 'RESOLVED': return 'text-green-700 bg-green-50 border-green-200';
      case 'ACTIVE': return 'text-blue-700 bg-blue-50 border-blue-200';
      case 'NEW': return 'text-purple-700 bg-purple-50 border-purple-200';
      case 'PENDING_CLIENT': return 'text-orange-700 bg-orange-50 border-orange-200';
      default: return 'text-slate-700 bg-slate-50 border-slate-200';
    }
  };

  // Helper for Priority Colors
  const getPriorityColor = (p: string) => {
    switch (p.toUpperCase()) {
      case 'P1': return 'text-red-700 bg-red-100';
      case 'P2': return 'text-orange-700 bg-orange-100';
      default: return 'text-slate-600 bg-slate-100';
    }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50">

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg">
            <Search className="h-5 w-5 text-white" />
          </div>
          <h1 className="text-xl font-bold text-slate-800">Support Explorer</h1>
        </div>
        <div className="text-sm text-slate-500">
          Logged in as <span className="font-semibold text-slate-700">reporting_api</span>
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">

        {/* Left Sidebar / Filter Panel */}
        <aside className="w-80 bg-white border-r border-slate-200 flex flex-col z-0 overflow-y-auto">
          <div className="p-5 border-b border-slate-100">
            <h2 className="text-sm font-semibold text-slate-900 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Filter className="h-4 w-4" /> Filters
            </h2>
            <form onSubmit={handleSearch} className="space-y-4">
              <div>
                <label className="text-xs font-medium text-slate-500 uppercase">Client Code</label>
                <input 
                  type="text" 
                  value={filters.clientCode}
                  onChange={(e) => handleFilterChange('clientCode', e.target.value)}
                  className="mt-1 block w-full rounded-md border-slate-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm px-3 py-2 border"
                  placeholder="e.g. chipotle"
                />
              </div>

              <div>
                <label className="text-xs font-medium text-slate-500 uppercase">Priority</label>
                <select
                  value={filters.priority}
                  onChange={(e) => handleFilterChange('priority', e.target.value)}
                  className="mt-1 block w-full rounded-md border-slate-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm px-3 py-2 border bg-white"
                >
                  <option value="">All Priorities</option>
                  <option value="P1">P1 - Critical</option>
                  <option value="P2">P2 - High</option>
                  <option value="P3">P3 - Medium</option>
                  <option value="P4">P4 - Low</option>
                </select>
              </div>

              <div>
                <label className="text-xs font-medium text-slate-500 uppercase">Type</label>
                <select
                  value={filters.ticketType}
                  onChange={(e) => handleFilterChange('ticketType', e.target.value)}
                  className="mt-1 block w-full rounded-md border-slate-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm px-3 py-2 border bg-white"
                >
                  <option value="">All Types</option>
                  <option value="INCIDENT">Incident</option>
                  <option value="SERVICE_REQUEST">Service Request</option>
                </select>
              </div>

              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="text-xs font-medium text-slate-500 uppercase">From</label>
                  <input 
                    type="date"
                    value={filters.dateFrom}
                    onChange={(e) => handleFilterChange('dateFrom', e.target.value)}
                    className="mt-1 block w-full rounded-md border-slate-300 shadow-sm focus:border-blue-500 sm:text-xs px-2 py-2 border"
                  />
                </div>
                <div>
                  <label className="text-xs font-medium text-slate-500 uppercase">To</label>
                  <input 
                    type="date"
                    value={filters.dateTo}
                    onChange={(e) => handleFilterChange('dateTo', e.target.value)}
                    className="mt-1 block w-full rounded-md border-slate-300 shadow-sm focus:border-blue-500 sm:text-xs px-2 py-2 border"
                  />
                </div>
              </div>

              <button
                type="submit"
                disabled={isSearching}
                className="w-full flex justify-center items-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-colors"
              >
                {isSearching ? <RefreshCw className="animate-spin h-4 w-4" /> : 'Apply Filters'}
              </button>
            </form>
          </div>

          {/* Recent Searches or Stats could go here */}
          <div className="p-5">
             <div className="text-xs text-slate-400">
               Enter criteria above to find tickets.
             </div>
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 flex overflow-hidden relative">

           {/* Ticket List Column */}
           <div className={`flex-1 flex flex-col bg-slate-50 border-r border-slate-200 transition-all duration-300 ${selectedTicket ? 'w-1/3 max-w-md hidden lg:flex' : 'w-full'}`}>

              {/* List Header */}
              <div className="p-4 bg-white border-b border-slate-200 flex justify-between items-center">
                 <h2 className="text-lg font-medium text-slate-800">Results</h2>
                 <span className="text-xs font-medium px-2 py-1 bg-slate-100 rounded-full text-slate-600">
                   {tickets.length} found
                 </span>
              </div>

              {/* List Body */}
              <div className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-3">
                {error && (
                  <div className="text-center p-4 bg-red-50 text-red-600 rounded-lg text-sm">
                    {error}
                  </div>
                )}

                {tickets.length === 0 && !isSearching && !error && (
                  <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                    <Search className="h-12 w-12 mb-3 opacity-20" />
                    <p>No tickets found.</p>
                  </div>
                )}

                {tickets.map(ticket => (
                  <div 
                    key={ticket.ticketId}
                    onClick={() => handleTicketSelect(ticket)}
                    className={`bg-white p-4 rounded-lg border shadow-sm cursor-pointer hover:shadow-md transition-all ${selectedTicket?.ticketId === ticket.ticketId ? 'ring-2 ring-blue-500 border-transparent' : 'border-slate-200 hover:border-blue-300'}`}
                  >
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex items-center gap-2">
                        <span className={`text-xs font-bold px-1.5 py-0.5 rounded ${getPriorityColor(ticket.priority)}`}>
                          {ticket.priority}
                        </span>
                        <span className="text-xs font-mono text-slate-500">#{ticket.ticketId}</span>
                      </div>
                      <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border uppercase tracking-wide ${getStatusColor(ticket.status)}`}>
                        {ticket.status}
                      </span>
                    </div>
                    <h3 className="text-sm font-semibold text-slate-800 line-clamp-2 mb-2">
                      {ticket.subject || "(No Subject)"}
                    </h3>
                    <div className="flex items-center gap-4 text-xs text-slate-500">
                      <div className="flex items-center gap-1">
                        <Tag className="h-3 w-3" />
                        {ticket.ticketClientCode}
                      </div>
                      <div className="flex items-center gap-1">
                        <Clock className="h-3 w-3" />
                        {new Date(ticket.created).toLocaleDateString()}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
           </div>

           {/* Ticket Detail View (Slide-over or conditional render) */}
           {(selectedTicket) && (
             <div className="flex-[2] bg-white flex flex-col h-full overflow-hidden absolute inset-0 lg:static z-20">
               {/* Detail Header */}
               <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between bg-white shadow-sm">
                 <div className="flex items-center gap-4">
                   <button 
                     onClick={() => setSelectedTicket(null)}
                     className="lg:hidden p-2 hover:bg-slate-100 rounded-full text-slate-500"
                   >
                     <ArrowLeft className="h-5 w-5" />
                   </button>
                   <div>
                     <div className="flex items-center gap-3 mb-1">
                       <h2 className="text-xl font-bold text-slate-900">#{selectedTicket.ticketId}</h2>
                       <span className={`text-xs font-bold px-2 py-0.5 rounded-full border uppercase ${getStatusColor(selectedTicket.status)}`}>
                          {selectedTicket.status}
                       </span>
                     </div>
                     <p className="text-sm text-slate-500 truncate max-w-md">{selectedTicket.subject}</p>
                   </div>
                 </div>
                 <div className="flex items-center gap-4 text-sm text-slate-600">
                   <div className="text-right hidden sm:block">
                     <div className="font-medium text-slate-900">{selectedTicket.ticketClientName}</div>
                     <div className="text-xs text-slate-500">Client</div>
                   </div>
                 </div>
               </div>

               {/* History Timeline */}
               <div className="flex-1 overflow-y-auto custom-scrollbar p-6 bg-slate-50/50">
                  {isLoadingHistory ? (
                    <div className="flex justify-center items-center h-full text-slate-500 gap-2">
                      <RefreshCw className="animate-spin h-5 w-5" /> Loading history...
                    </div>
                  ) : (
                    <div className="max-w-3xl mx-auto">
                      <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-6">Activity Timeline</h3>
                      <div className="space-y-6">
                        {history.map((item, index) => (
                          <div key={item.id} className="relative pl-8">
                            {/* Vertical Line */}
                            {index !== history.length - 1 && (
                              <div className="absolute left-[11px] top-6 bottom-[-24px] w-0.5 bg-slate-200"></div>
                            )}

                            {/* Icon Logic */}
                            <div className={`absolute left-0 top-1 w-6 h-6 rounded-full border-2 flex items-center justify-center bg-white z-10 
                              ${item.source === 'workflow' ? 'border-purple-400 text-purple-500' : 
                                item.comment ? 'border-blue-400 text-blue-500' : 'border-slate-300 text-slate-400'}`}>
                              {item.comment ? <MessageSquare className="h-3 w-3" /> : 
                               item.source === 'workflow' ? <CheckCircle2 className="h-3 w-3" /> : 
                               <AlertCircle className="h-3 w-3" />}
                            </div>

                            {/* Content Card */}
                            <div className="bg-white rounded-lg border border-slate-200 shadow-sm p-4">
                              <div className="flex justify-between items-start mb-2">
                                <div className="text-xs font-medium text-slate-500 flex items-center gap-2">
                                  <span className="font-bold text-slate-700">{item.actorName || item.actorId || "System"}</span>
                                  <span>via {item.source || "unknown"}</span>
                                </div>
                                <span className="text-[10px] text-slate-400">
                                  {new Date(item.created).toLocaleString()}
                                </span>
                              </div>

                              {/* Comment Render */}
                              {item.comment && (
                                <div className="mt-2 text-sm text-slate-800 bg-slate-50 p-3 rounded border border-slate-100 prose prose-sm max-w-none">
                                  <div dangerouslySetInnerHTML={{ __html: item.comment.content }} />
                                </div>
                              )}

                              {/* Field Updates Render */}
                              {item.fieldUpdates && item.fieldUpdates.length > 0 && (
                                <div className="mt-2 space-y-1">
                                  {item.fieldUpdates.map((update, idx) => (
                                    <div key={idx} className="text-xs flex items-center gap-2 bg-yellow-50 text-yellow-800 px-2 py-1 rounded w-fit">
                                      <span className="font-semibold">{update.field}:</span>
                                      <span className="line-through opacity-60">{update.oldValue}</span>
                                      <ChevronRight className="h-3 w-3" />
                                      <span className="font-bold">{update.newValue}</span>
                                    </div>
                                  ))}
                                </div>
                              )}

                              {/* Workflow fallback if no specific comment/field update but is workflow */}
                              {item.source === 'workflow' && !item.comment && (!item.fieldUpdates || item.fieldUpdates.length === 0) && (
                                <div className="text-xs text-slate-500 italic">
                                  Workflow automation executed.
                                </div>
                              )}

                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
               </div>
             </div>
           )}

           {/* Empty State for Details */}
           {!selectedTicket && (
             <div className="hidden lg:flex flex-[2] bg-slate-100 items-center justify-center text-slate-400 flex-col">
                <div className="bg-white p-6 rounded-full shadow-sm mb-4">
                  <Filter className="h-10 w-10 text-slate-300" />
                </div>
                <p className="font-medium">Select a ticket to view history</p>
             </div>
           )}

        </main>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import LoginForm from './components/LoginForm';
import Dashboard from './components/Dashboard';
import { ViewState } from './types';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.LOGIN);

  const handleLoginSuccess = () => {
    setCurrentView(ViewState.DASHBOARD);
  };

  return (
    <div className="antialiased text-slate-900">
      {currentView === ViewState.LOGIN && (
        <LoginForm onLoginSuccess={handleLoginSuccess} />
      )}
      {currentView === ViewState.DASHBOARD && (
        <Dashboard />
      )}
    </div>
  );
}

export default App;

import { Ticket, SearchResponse, HistoryResponse, FilterParams } from '../types';

// We use a CORS proxy because the Amelia API does not allow cross-origin requests from the browser.
// In a production app, this would be handled by a backend server/proxy.
const PROXY_URL = 'https://corsproxy.io/?';

const AUTH_URL = 'https://support.amelia.com/AmeliaRest/api/v1/aiops/token/get';
const BASE_REPORTING_URL = 'https://support.amelia.com/api/reporting/export';
const BASE_TICKET_URL = 'https://support.amelia.com/api/tickets';

export class ApiService {
  private static token: string | null = null;

  static setToken(token: string) {
    this.token = token;
  }

  static getToken(): string | null {
    return this.token;
  }

  // Helper to wrap URLs with the CORS proxy
  // We encode the target URL so query parameters are processed by the target API, not the proxy
  private static getProxiedUrl(targetUrl: string): string {
    return `${PROXY_URL}${encodeURIComponent(targetUrl)}`;
  }

  static async login(username: string, password: string): Promise<string> {
    const response = await fetch(this.getProxiedUrl(AUTH_URL), {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        ameliaUrl: "https://support.amelia.com/Amelia",
        username,
        password
      }),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Authentication failed: ${response.status} - ${errorText}`);
    }

    const text = await response.text();
    try {
      const json = JSON.parse(text);
      // Handle cases where token might be a simple string or inside a JSON object
      return json.token || json; 
    } catch {
      return text;
    }
  }

  static async searchTickets(filters: FilterParams): Promise<SearchResponse> {
    if (!this.token) throw new Error('Not authenticated');

    const queryParts: string[] = [];

    if (filters.clientCode) queryParts.push(`ticketClientCode:${filters.clientCode}`);
    if (filters.clientName) queryParts.push(`ticketClientName:${filters.clientName}`);
    if (filters.priority) queryParts.push(`priority:${filters.priority}`);
    if (filters.ticketType) queryParts.push(`ticketType:${filters.ticketType}`);

    // Date handling
    if (filters.dateFrom && filters.dateTo) {
      const from = `${filters.dateFrom}T00:00:00`;
      const to = `${filters.dateTo}T23:59:59.999`;
      queryParts.push(`created:["${from}" TO "${to}"]`);
    }

    const queryString = queryParts.join(' AND ');
    const encodedQuery = encodeURIComponent(queryString);

    // Construct the full target URL first
    const targetUrl = `${BASE_REPORTING_URL}?index=tasks&showTotal=true&page=0&size=50&q=${encodedQuery}`;

    // Pass the full URL to the proxy
    const response = await fetch(this.getProxiedUrl(targetUrl), {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${this.token}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Search failed: ${response.statusText} - ${errorText}`);
    }

    return await response.json();
  }

  static async getTicketHistory(ticketId: number): Promise<HistoryResponse> {
    if (!this.token) throw new Error('Not authenticated');

    const targetUrl = `${BASE_TICKET_URL}/${ticketId}/history`;

    const response = await fetch(this.getProxiedUrl(targetUrl), {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${this.token}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch history: ${response.statusText}`);
    }

    return await response.json();
  }
}

