import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Ticket, TicketHistoryItem, AiAnalysisResult, GeminiModel } from '../types';

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    score: {
      type: Type.NUMBER,
      description: "A quality score from 1 to 10 based on handling best practices.",
    },
    summary: {
      type: Type.STRING,
      description: "A concise 1-sentence summary of the ticket handling quality.",
    },
    strengths: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of positive aspects (e.g., fast response, clear communication).",
    },
    weaknesses: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of negative aspects (e.g., missed SLA, vague updates).",
    },
    rcaDetected: {
      type: Type.BOOLEAN,
      description: "True if a Root Cause Analysis was provided or discussed.",
    },
  },
  required: ["score", "summary", "strengths", "weaknesses", "rcaDetected"],
};

export class AiService {

  static async getModels(apiKey: string): Promise<GeminiModel[]> {
    try {
      // Direct REST call to list models using the provided key
      const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?key=${apiKey}`);

      if (!response.ok) {
        throw new Error(`Failed to fetch models: ${response.statusText}`);
      }

      const data = await response.json();

      if (!data.models) return [];

      return data.models
        .filter((m: any) => m.supportedGenerationMethods && m.supportedGenerationMethods.includes("generateContent"))
        .map((m: any) => ({
          id: m.name.replace('models/', ''),
          displayName: m.displayName || m.name
        }));
    } catch (error) {
      console.error("Error fetching models:", error);
      throw error;
    }
  }

  static async analyzeTicket(
    ticket: Ticket, 
    history: TicketHistoryItem[], 
    modelName: string,
    apiKey: string
  ): Promise<AiAnalysisResult> {

    // Initialize GoogleGenAI with the user-provided key
    const ai = new GoogleGenAI({ apiKey: apiKey });

    // Construct a context-rich prompt
    const historyText = history.map(h => {
      let details = '';
      if (h.comment) {
        // Strip basic HTML for cleaner token usage
        const textContent = h.comment.content.replace(/<[^>]*>/g, ' ');
        details = `Comment: "${textContent}"`;
      } else if (h.fieldUpdates && h.fieldUpdates.length > 0) {
        details = `Updates: ${h.fieldUpdates.map(u => `${u.field} changed from ${u.oldValue} to ${u.newValue}`).join(', ')}`;
      } else {
        details = 'System/Workflow action';
      }
      return `[${h.created}] ${h.actorName || h.actorId} (${h.source}): ${details}`;
    }).join('\n');

    const prompt = `
      You are a QA Auditor for IT Support Tickets.
      Analyze the following ticket and its history.

      TICKET METADATA:
      ID: ${ticket.ticketId}
      Subject: ${ticket.subject}
      Priority: ${ticket.priority}
      Status: ${ticket.status}
      Client: ${ticket.ticketClientName}

      FULL HISTORY LOG:
      ${historyText}

      Evaluate based on:
      1. Timeliness (Response time, resolution time vs priority).
      2. Transparency (Clear updates to the client).
      3. Detail (Technical depth suitable for the issue).
      4. Root Cause Analysis (Was the root cause identified?).
      5. Follow-up (Was confirmation requested before closing?).

      Provide a strict JSON response.
    `;

    try {
      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: analysisSchema,
        },
      });

      const jsonText = response.text;
      if (!jsonText) throw new Error("Empty response from AI");

      const parsed = JSON.parse(jsonText);

      return {
        ticketId: ticket.ticketId,
        ...parsed
      };

    } catch (error) {
      console.error("AI Analysis failed for ticket " + ticket.ticketId, error);
      // Return a fallback error result so the batch processing continues
      return {
        ticketId: ticket.ticketId,
        score: 0,
        summary: "Analysis failed due to API error.",
        strengths: [],
        weaknesses: ["Error processing ticket"],
        rcaDetected: false
      };
    }
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { ApiService } from '../services/api';
import { AiService } from '../services/ai';
import { Ticket, AiConfig, AiAnalysisResult, GeminiModel } from '../types';
import { 
  X, 
  Bot, 
  Play, 
  Settings2, 
  AlertCircle, 
  CheckCircle2, 
  ChevronDown, 
  ChevronUp,
  BrainCircuit,
  Key,
  RefreshCw,
  Loader2
} from 'lucide-react';

interface AiAnalysisModalProps {
  isOpen: boolean;
  onClose: () => void;
  tickets: Ticket[];
}

const AiAnalysisModal: React.FC<AiAnalysisModalProps> = ({ isOpen, onClose, tickets }) => {
  const [step, setStep] = useState<'config' | 'processing' | 'results'>('config');
  const [config, setConfig] = useState<AiConfig>({
    apiKey: '',
    model: 'gemini-2.0-flash-lite-preview', // Default fallback
    rpm: 10
  });

  const [availableModels, setAvailableModels] = useState<GeminiModel[]>([]);
  const [isLoadingModels, setIsLoadingModels] = useState(false);
  const [modelError, setModelError] = useState('');

  const [progress, setProgress] = useState(0);
  const [currentProcessingId, setCurrentProcessingId] = useState<number | null>(null);
  const [results, setResults] = useState<AiAnalysisResult[]>([]);
  const [expandedResultId, setExpandedResultId] = useState<number | null>(null);

  const isRunningRef = useRef(false);

  useEffect(() => {
    if (isOpen) {
      // Reset state when opening
      setStep('config');
      setResults([]);
      setProgress(0);
      isRunningRef.current = false;
      // Note: We don't reset API key or models to be friendly to user re-opening
    }
  }, [isOpen]);

  const fetchModels = async () => {
    if (!config.apiKey) {
      setModelError("Please enter an API Key");
      return;
    }

    setIsLoadingModels(true);
    setModelError('');
    setAvailableModels([]);

    try {
      const models = await AiService.getModels(config.apiKey);
      setAvailableModels(models);

      // Auto-select a preferred model if available
      const preferred = models.find(m => m.id.includes('flash-lite')) || models.find(m => m.id.includes('flash'));
      if (preferred) {
        setConfig(prev => ({ ...prev, model: preferred.id }));
      } else if (models.length > 0) {
        setConfig(prev => ({ ...prev, model: models[0].id }));
      }
    } catch (err: any) {
      setModelError("Failed to load models. Please check your API Key.");
    } finally {
      setIsLoadingModels(false);
    }
  };

  const startAnalysis = async () => {
    if (!config.apiKey) return;

    setStep('processing');
    setResults([]);
    setProgress(0);
    isRunningRef.current = true;

    const delayMs = 60000 / config.rpm;

    // We only process the first 50 tickets to be safe/sane for a demo
    const ticketsToProcess = tickets.slice(0, 50);

    for (let i = 0; i < ticketsToProcess.length; i++) {
      if (!isRunningRef.current) break;

      const ticket = ticketsToProcess[i];
      setCurrentProcessingId(ticket.ticketId);

      try {
        // 1. Fetch History
        const historyResponse = await ApiService.getTicketHistory(ticket.ticketId);

        // 2. Call Gemini
        const result = await AiService.analyzeTicket(
            ticket, 
            historyResponse.content, 
            config.model,
            config.apiKey
        );

        setResults(prev => [...prev, result]);
      } catch (err) {
        console.error(`Error processing ticket ${ticket.ticketId}`, err);
        // Add a failed record
        setResults(prev => [...prev, {
            ticketId: ticket.ticketId,
            score: 0,
            summary: "Failed to fetch data or analyze.",
            strengths: [],
            weaknesses: ["System error during processing"],
            rcaDetected: false
        }]);
      }

      setProgress(i + 1);

      // Rate limit delay (skip on last item)
      if (i < ticketsToProcess.length - 1 && isRunningRef.current) {
        await new Promise(resolve => setTimeout(resolve, delayMs));
      }
    }

    setStep('results');
    isRunningRef.current = false;
  };

  const handleStop = () => {
    isRunningRef.current = false;
    setStep('results'); // Show what we have so far
  };

  const toggleExpand = (id: number) => {
    setExpandedResultId(expandedResultId === id ? null : id);
  };

  const getScoreColor = (score: number) => {
    if (score >= 8) return 'text-green-600 bg-green-50 border-green-200';
    if (score >= 5) return 'text-yellow-600 bg-yellow-50 border-yellow-200';
    return 'text-red-600 bg-red-50 border-red-200';
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl h-[80vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden border border-slate-200">

        {/* Header */}
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div className="flex items-center gap-2">
            <div className="bg-purple-100 p-2 rounded-lg">
               <Bot className="h-5 w-5 text-purple-600" />
            </div>
            <div>
                <h2 className="text-lg font-bold text-slate-800">AI Quality Audit</h2>
                <p className="text-xs text-slate-500">Powered by Gemini</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full text-slate-500 transition-colors">
            <X className="h-5 w-5" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">

          {step === 'config' && (
            <div className="space-y-6">
                <div className="bg-blue-50 border border-blue-100 p-4 rounded-xl flex gap-3">
                    <BrainCircuit className="h-6 w-6 text-blue-600 flex-shrink-0" />
                    <div className="text-sm text-blue-800">
                        <p className="font-semibold mb-1">About this analysis</p>
                        This process will read the filtered tickets ({tickets.length} total) and their full history logs. 
                        Provide your Gemini API Key to select a model and start the audit.
                    </div>
                </div>

                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Gemini API Key</label>
                        <div className="flex gap-2">
                           <div className="relative flex-1">
                              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <Key className="h-4 w-4 text-slate-400" />
                              </div>
                              <input 
                                  type="password"
                                  value={config.apiKey}
                                  onChange={(e) => setConfig({...config, apiKey: e.target.value})}
                                  placeholder="Enter API Key"
                                  className="w-full rounded-lg border-slate-300 shadow-sm focus:border-purple-500 focus:ring-purple-500 py-2.5 pl-10 pr-3 bg-white text-slate-900"
                              />
                           </div>
                           <button 
                             onClick={fetchModels}
                             disabled={!config.apiKey || isLoadingModels}
                             className="px-4 py-2 bg-slate-100 text-slate-700 font-medium rounded-lg hover:bg-slate-200 disabled:opacity-50 transition-colors flex items-center gap-2"
                           >
                             {isLoadingModels ? <Loader2 className="animate-spin h-4 w-4"/> : <RefreshCw className="h-4 w-4" />}
                             Load Models
                           </button>
                        </div>
                        {modelError && <p className="text-red-600 text-xs mt-1">{modelError}</p>}
                    </div>

                    <div className={`transition-opacity duration-300 ${availableModels.length > 0 ? 'opacity-100' : 'opacity-50 pointer-events-none'}`}>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Select Model</label>
                        <select 
                            value={config.model}
                            onChange={(e) => setConfig({...config, model: e.target.value})}
                            disabled={availableModels.length === 0}
                            className="w-full rounded-lg border-slate-300 shadow-sm focus:border-purple-500 focus:ring-purple-500 py-2.5 px-3 bg-white text-slate-900 disabled:bg-slate-100"
                        >
                            {availableModels.length === 0 && <option>Enter API Key to load models...</option>}
                            {availableModels.map(m => (
                              <option key={m.id} value={m.id}>{m.displayName} ({m.id})</option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Rate Limit (Requests Per Minute)</label>
                        <div className="flex items-center gap-4">
                            <input 
                                type="number" 
                                min="1" 
                                max="60"
                                value={config.rpm}
                                onChange={(e) => setConfig({...config, rpm: parseInt(e.target.value) || 10})}
                                className="w-32 rounded-lg border-slate-300 shadow-sm focus:border-purple-500 focus:ring-purple-500 py-2.5 px-3 text-slate-900"
                            />
                            <span className="text-sm text-slate-500">
                                Approx {(60 / config.rpm).toFixed(1)}s delay between tickets.
                            </span>
                        </div>
                    </div>
                </div>
            </div>
          )}

          {step === 'processing' && (
             <div className="flex flex-col items-center justify-center h-full py-10 space-y-6">
                <div className="relative h-24 w-24">
                     <svg className="animate-spin h-full w-full text-purple-200" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                     </svg>
                     <div className="absolute inset-0 flex items-center justify-center text-xs font-bold text-purple-600">
                        {Math.round((progress / tickets.length) * 100)}%
                     </div>
