import React, { useState, useEffect, useRef } from 'react';
import { ApiService } from '../services/api';
import { AiService } from '../services/ai';
import { Ticket, AiConfig, AiAnalysisResult, GeminiModel } from '../types';
import { 
  X, 
  Bot, 
  Play, 
  Settings2, 
  AlertCircle, 
  CheckCircle2, 
  ChevronDown, 
  ChevronUp,
  BrainCircuit,
  Key,
  RefreshCw,
  Loader2
} from 'lucide-react';

interface AiAnalysisModalProps {
  isOpen: boolean;
  onClose: () => void;
  tickets: Ticket[];
}

const AiAnalysisModal: React.FC<AiAnalysisModalProps> = ({ isOpen, onClose, tickets }) => {
  const [step, setStep] = useState<'config' | 'processing' | 'results'>('config');
  const [config, setConfig] = useState<AiConfig>({
    apiKey: '',
    model: 'gemini-2.0-flash-lite-preview', // Default fallback
    rpm: 10
  });

  const [availableModels, setAvailableModels] = useState<GeminiModel[]>([]);
  const [isLoadingModels, setIsLoadingModels] = useState(false);
  const [modelError, setModelError] = useState('');

  const [progress, setProgress] = useState(0);
  const [currentProcessingId, setCurrentProcessingId] = useState<number | null>(null);
  const [results, setResults] = useState<AiAnalysisResult[]>([]);
  const [expandedResultId, setExpandedResultId] = useState<number | null>(null);

  const isRunningRef = useRef(false);

  useEffect(() => {
    if (isOpen) {
      // Reset state when opening
      setStep('config');
      setResults([]);
      setProgress(0);
      isRunningRef.current = false;
      // Note: We don't reset API key to be friendly to user re-opening
    }
  }, [isOpen]);

  // When API Key changes, clear the models list so the user is forced to reload/verify
  useEffect(() => {
    setAvailableModels([]);
    setModelError('');
  }, [config.apiKey]);

  const fetchModels = async () => {
    if (!config.apiKey) {
      setModelError("Please enter an API Key");
      return;
    }

    setIsLoadingModels(true);
    setModelError('');
    setAvailableModels([]);

    try {
      const models = await AiService.getModels(config.apiKey);
      setAvailableModels(models);

      // Auto-select a preferred model if available
      const preferred = models.find(m => m.id.includes('flash-lite')) || models.find(m => m.id.includes('flash'));
      if (preferred) {
        setConfig(prev => ({ ...prev, model: preferred.id }));
      } else if (models.length > 0) {
        setConfig(prev => ({ ...prev, model: models[0].id }));
      }
    } catch (err: any) {
      console.error(err);
      setModelError("Failed to load models. Please check your API Key.");
    } finally {
      setIsLoadingModels(false);
    }
  };

  const startAnalysis = async () => {
    if (!config.apiKey) return;

    setStep('processing');
    setResults([]);
    setProgress(0);
    isRunningRef.current = true;

    const delayMs = 60000 / config.rpm;

    // We only process the first 50 tickets to be safe/sane for a demo
    const ticketsToProcess = tickets.slice(0, 50);

    for (let i = 0; i < ticketsToProcess.length; i++) {
      if (!isRunningRef.current) break;

      const ticket = ticketsToProcess[i];
      setCurrentProcessingId(ticket.ticketId);

      try {
        // 1. Fetch History
        const historyResponse = await ApiService.getTicketHistory(ticket.ticketId);

        // 2. Call Gemini
        const result = await AiService.analyzeTicket(
            ticket, 
            historyResponse.content, 
            config.model,
            config.apiKey
        );

        setResults(prev => [...prev, result]);
      } catch (err) {
        console.error(`Error processing ticket ${ticket.ticketId}`, err);
        // Add a failed record
        setResults(prev => [...prev, {
            ticketId: ticket.ticketId,
            score: 0,
            summary: "Failed to fetch data or analyze.",
            strengths: [],
            weaknesses: ["System error during processing"],
            rcaDetected: false
        }]);
      }

      setProgress(i + 1);

      // Rate limit delay (skip on last item)
      if (i < ticketsToProcess.length - 1 && isRunningRef.current) {
        await new Promise(resolve => setTimeout(resolve, delayMs));
      }
    }

    setStep('results');
    isRunningRef.current = false;
  };

  const handleStop = () => {
    isRunningRef.current = false;
    setStep('results'); // Show what we have so far
  };

  const toggleExpand = (id: number) => {
    setExpandedResultId(expandedResultId === id ? null : id);
  };

  const getScoreColor = (score: number) => {
    if (score >= 8) return 'text-green-600 bg-green-50 border-green-200';
    if (score >= 5) return 'text-yellow-600 bg-yellow-50 border-yellow-200';
    return 'text-red-600 bg-red-50 border-red-200';
