                                      <h4 className="text-xs font-bold text-green-700 uppercase mb-2 flex items-center gap-1">
                                          <CheckCircle2 className="h-3 w-3"/> Strengths
                                      </h4>
                                      <ul className="text-xs text-slate-600 space-y-1 list-disc pl-4">
