                    Stop
                </button>
            )}

            {step === 'results' && (
                <button 
                    onClick={() => setStep('config')}
                    className="px-4 py-2 bg-slate-800 hover:bg-slate-900 text-white text-sm font-medium rounded-lg"
                >
                    New Analysis
                </button>
            )}
        </div>
      </div>
    </div>
  );
};

