// We use a CORS proxy because the Amelia API does not allow cross-origin requests from the browser.
// In a production app, this would be handled by a backend server/proxy.
// Default proxy URL
const DEFAULT_PROXY_URL = 'https://corsproxy.io/?';

const AUTH_URL = 'https://support.amelia.com/AmeliaRest/api/v1/aiops/token/get';
const BASE_REPORTING_URL = 'https://support.amelia.com/api/reporting/export';
const BASE_TICKET_URL = 'https://support.amelia.com/api/tickets';

export class ApiService {
  private static token: string | null = null;
  private static proxyEnabled: boolean = true;
  private static proxyUrl: string = DEFAULT_PROXY_URL;

  static setToken(token: string) {
    this.token = token;
  }

  static getToken(): string | null {
    return this.token;
  }

  static setProxyConfig(enabled: boolean, url: string) {
    this.proxyEnabled = enabled;
    this.proxyUrl = url;
  }

  static getProxyConfig() {
    return { enabled: this.proxyEnabled, url: this.proxyUrl };
  }

  // Helper to wrap URLs with the CORS proxy
  // We encode the target URL so query parameters are processed by the target API, not the proxy
  private static getProxiedUrl(targetUrl: string): string {
    if (!this.proxyEnabled) {
      return targetUrl;
    }
    return `${this.proxyUrl}${encodeURIComponent(targetUrl)}`;
  }

  static async login(username: string, password: string): Promise<string> {
    const response = await fetch(this.getProxiedUrl(AUTH_URL), {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        ameliaUrl: "https://support.amelia.com/Amelia",
        username,
        password
      }),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Authentication failed: ${response.status} - ${errorText}`);
    }

    const text = await response.text();
    try {
      const json = JSON.parse(text);

      // Case 1: Response is a plain string (just the token)
      if (typeof json === 'string') {
        return json;
      }

      // Case 2: Response is a JSON object
      if (typeof json === 'object' && json !== null) {
        // 2a. Check explicit token keys, prioritizing aiOpsAccessToken as requested
        const commonKeys = ['aiOpsAccessToken', 'token', 'access_token', 'accessToken', 'data', 'sessionId', 'id_token', 'idToken'];
        for (const key of commonKeys) {
          if (json[key] && typeof json[key] === 'string') {
            return json[key];
          }
        }

        const keys = Object.keys(json);

        // 2b. Check for any key containing "token" (case insensitive)
        for (const key of keys) {
          if (key.toLowerCase().includes('token') && typeof json[key] === 'string') {
            return json[key];
          }
        }

        // 2c. Heuristic: Look for the first value that is a string and looks like a token (length > 10)
        // This avoids boolean flags or short status codes
        for (const key of keys) {
          const val = json[key];
          if (typeof val === 'string' && val.length > 15) {
            return val;
          }
        }

        // 2d. If there is exactly one value and it's a string (even if short), take it
        const values = Object.values(json);
        if (values.length === 1 && typeof values[0] === 'string') {
          return values[0] as string;
        }

        // If we reach here, we have an object but couldn't identify the token
        console.error("Token parsing failed. Structure:", JSON.stringify(json));
        throw new Error(`Could not find token in response: ${JSON.stringify(json)}`);
      }

      return String(json); 
    } catch (e) {
      // If JSON parse fails, assume the text body IS the token
      if (e instanceof SyntaxError) {
        return text;
      }
      throw e;
    }
  }

  static async searchTickets(filters: FilterParams): Promise<SearchResponse> {
    if (!this.token) throw new Error('Not authenticated');

    const queryParts: string[] = [];

    if (filters.clientCode) queryParts.push(`ticketClientCode:${filters.clientCode}`);
    if (filters.clientName) queryParts.push(`ticketClientName:${filters.clientName}`);
    if (filters.priority) queryParts.push(`priority:${filters.priority}`);
    if (filters.ticketType) queryParts.push(`ticketType:${filters.ticketType}`);

    // Subject filter - wrap in parentheses to handle spaces safely (e.g. subject:(system down))
    if (filters.subject) {
        queryParts.push(`subject:(${filters.subject})`);
    }

    // Date handling
    if (filters.dateFrom && filters.dateTo) {
      const from = `${filters.dateFrom}T00:00:00`;
      const to = `${filters.dateTo}T23:59:59.999`;
      queryParts.push(`created:["${from}" TO "${to}"]`);
    }

    const queryString = queryParts.join(' AND ');
    const encodedQuery = encodeURIComponent(queryString);

    // Construct the full target URL first
    const targetUrl = `${BASE_REPORTING_URL}?index=tasks&showTotal=true&page=0&size=50&q=${encodedQuery}`;

    // Pass the full URL to the proxy
    const response = await fetch(this.getProxiedUrl(targetUrl), {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${this.token}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Search failed: ${response.statusText} - ${errorText}`);
    }

    return await response.json();
  }

  static async getTicketHistory(ticketId: number): Promise<HistoryResponse> {
    if (!this.token) throw new Error('Not authenticated');

    const targetUrl = `${BASE_TICKET_URL}/${ticketId}/history/all`;

    const response = await fetch(this.getProxiedUrl(targetUrl), {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${this.token}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch history: ${response.statusText}`);
    }

    return await response.json();
  }
}

import React, { useState, useMemo } from 'react';
import { ApiService } from '../services/api';
import { Ticket, TicketHistoryItem, FilterParams, AiAnalysisResult } from '../types';
import AiAnalysisModal from './AiAnalysisModal';
import { 
  Search, 
  Filter, 
  Clock, 
  CheckCircle2, 
  AlertCircle, 
  MessageSquare, 
  ChevronRight,
  ArrowLeft,
  RefreshCw,
  Tag,
  User,
  Sparkles,
  Download,
  ArrowUpDown,
  ListFilter
} from 'lucide-react';

const Dashboard: React.FC = () => {
  // --- STATE ---
  const [filters, setFilters] = useState<FilterParams>({
    clientCode: '',
    clientName: '',
    priority: '',
    ticketType: '',
    subject: '',
    dateFrom: new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0],
    dateTo: new Date().toISOString().split('T')[0]
  });

  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);
  const [history, setHistory] = useState<TicketHistoryItem[]>([]);

  // AI Results Map: TicketID -> Result
  const [aiResults, setAiResults] = useState<Record<number, AiAnalysisResult>>({});

  // UI State
  const [isSearching, setIsSearching] = useState(false);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const [error, setError] = useState('');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);

  // Sorting & AI Filters
  const [sortOption, setSortOption] = useState<'date_desc' | 'date_asc' | 'score_asc' | 'score_desc'>('date_desc');
  const [filterRcaOnly, setFilterRcaOnly] = useState(false);

  // --- HANDLERS ---

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setIsSearching(true);
    setError('');
    setSelectedTicket(null);
    setAiResults({}); // Clear previous AI results on new search

    try {
      const response = await ApiService.searchTickets(filters);
      setTickets(response.searchResults);
    } catch (err) {
      console.error(err);
      setError('Failed to fetch tickets. Please check your filters.');
    } finally {
      setIsSearching(false);
    }
  };

  const handleTicketSelect = async (ticket: Ticket) => {
    setSelectedTicket(ticket);
    setIsLoadingHistory(true);
    try {
      const response = await ApiService.getTicketHistory(ticket.ticketId);
      setHistory(response.content);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoadingHistory(false);
    }
  };

  const handleFilterChange = (key: keyof FilterParams, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const handleAnalysisUpdate = (result: AiAnalysisResult) => {
    setAiResults(prev => ({
        ...prev,
        [result.ticketId]: result
    }));
  };

  const handleExport = () => {
    // 1. Headers
    const headers = [
        "Ticket ID", "Client", "Subject", "Priority", "Status", "Type", "Created", "Resolved", 
        "AI Score", "AI Summary", "RCA Detected", "Strengths", "Weaknesses", "AI Error"
    ];

    // 2. Helper to escape CSV
    const escapeCsv = (field: any) => {
        if (field === null || field === undefined) return '';
        const stringField = String(field);
        if (stringField.includes(',') || stringField.includes('"') || stringField.includes('\n')) {
          return `"${stringField.replace(/"/g, '""')}"`;
        }
        return stringField;
    };

    // 3. Map Data
    // We export the filtered/sorted view or the whole current search result? 
    // Usually exporting what matches current filters is best.
    const csvRows = processedTickets.map(t => {
        const ai = aiResults[t.ticketId];
        return [
            t.ticketId,
            t.ticketClientName,
            t.subject,
            t.priority,
            t.status,
            t.ticketType,
            t.created,
            t.resolved || '',
            ai ? ai.score : '',
            ai ? ai.summary : '',
            ai ? (ai.rcaDetected ? "Yes" : "No") : '',
            ai ? ai.strengths.join('; ') : '',
            ai ? ai.weaknesses.join('; ') : '',
            ai ? (ai.error || '') : ''
        ].map(escapeCsv).join(',');
    });

    const csvContent = [headers.join(','), ...csvRows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `support_analysis_export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- DERIVED STATE ---

  const processedTickets = useMemo(() => {
    let result = [...tickets];

    // 1. AI Filters
    if (filterRcaOnly) {
        result = result.filter(t => aiResults[t.ticketId]?.rcaDetected);
    }

    // 2. Sorting
    result.sort((a, b) => {
        const dateA = new Date(a.created).getTime();
        const dateB = new Date(b.created).getTime();
        const scoreA = aiResults[a.ticketId]?.score || 0;
        const scoreB = aiResults[b.ticketId]?.score || 0;

        switch (sortOption) {
            case 'date_asc': return dateA - dateB;
            case 'date_desc': return dateB - dateA;
            case 'score_asc': 
                // Put un-scored tickets at the end for clarity? Or treat as 0.
                if (!aiResults[a.ticketId] && aiResults[b.ticketId]) return 1;
                if (aiResults[a.ticketId] && !aiResults[b.ticketId]) return -1;
                return scoreA - scoreB;
            case 'score_desc':
                return scoreB - scoreA;
            default: return 0;
        }
    });

    return result;
  }, [tickets, aiResults, sortOption, filterRcaOnly]);

  const stats = useMemo(() => {
     const analyzedCount = Object.keys(aiResults).length;
     if (analyzedCount === 0) return null;

     const totalScore = Object.values(aiResults).reduce((acc, curr) => acc + (curr.score || 0), 0);
     const rcaCount = Object.values(aiResults).filter(r => r.rcaDetected).length;

     return {
        avgScore: (totalScore / analyzedCount).toFixed(1),
        rcaPercentage: Math.round((rcaCount / analyzedCount) * 100)
     };
  }, [aiResults]);


  // --- HELPERS ---
  const getStatusColor = (status: string) => {
    switch (status.toUpperCase()) {
      case 'RESOLVED': return 'text-green-700 bg-green-50 border-green-200';
      case 'ACTIVE': return 'text-blue-700 bg-blue-50 border-blue-200';
      case 'NEW': return 'text-purple-700 bg-purple-50 border-purple-200';
      case 'PENDING_CLIENT': return 'text-orange-700 bg-orange-50 border-orange-200';
      default: return 'text-slate-700 bg-slate-50 border-slate-200';
    }
  };

  const getPriorityColor = (p: string) => {
    switch (p.toUpperCase()) {
      case 'P1': return 'text-red-700 bg-red-100';
      case 'P2': return 'text-orange-700 bg-orange-100';
      default: return 'text-slate-600 bg-slate-100';
    }
  };

  const getScoreColor = (score: number) => {
      if (score >= 8) return 'text-green-600 bg-green-50 border-green-200';
      if (score >= 5) return 'text-yellow-600 bg-yellow-50 border-yellow-200';
      return 'text-red-600 bg-red-50 border-red-200';
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50">

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg">
            <Search className="h-5 w-5 text-white" />
          </div>
          <h1 className="text-xl font-bold text-slate-800">Support Explorer</h1>
        </div>
        <div className="flex items-center gap-4">
             {/* Global Stats Widget if AI is active */}
             {stats && (
                 <div className="hidden md:flex items-center gap-4 mr-4 px-4 py-1.5 bg-slate-50 rounded-lg border border-slate-200">
                     <div className="flex flex-col items-center">
                         <span className="text-[10px] uppercase text-slate-400 font-bold">Avg Quality</span>
                         <span className={`text-sm font-bold ${Number(stats.avgScore) >= 8 ? 'text-green-600' : 'text-slate-700'}`}>{stats.avgScore}</span>
                     </div>
                     <div className="w-px h-6 bg-slate-200"></div>
                     <div className="flex flex-col items-center">
                         <span className="text-[10px] uppercase text-slate-400 font-bold">RCA Rate</span>
                         <span className="text-sm font-bold text-blue-600">{stats.rcaPercentage}%</span>
                     </div>
                 </div>
             )}
            <div className="text-sm text-slate-500">
                <User className="h-4 w-4 inline mr-2"/>
                <span className="font-semibold text-slate-700">reporting_api</span>
            </div>
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">

        {/* Left Sidebar / Filter Panel */}
        <aside className="w-72 bg-white border-r border-slate-200 flex flex-col z-0 overflow-y-auto flex-shrink-0">
          <div className="p-5 border-b border-slate-100">
            <h2 className="text-sm font-semibold text-slate-900 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Filter className="h-4 w-4" /> Filters
            </h2>
            <form onSubmit={handleSearch} className="space-y-4">
              <div>
                <label className="text-xs font-medium text-slate-500 uppercase">Client Code</label>
                <input 
                  type="text" 
                  value={filters.clientCode}
                  onChange={(e) => handleFilterChange('clientCode', e.target.value)}
                  className="mt-1 block w-full rounded-md border-slate-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm px-3 py-2 border bg-white text-slate-900"
                  placeholder="e.g. chipotle"
                />
              </div>

              <div>
                <label className="text-xs font-medium text-slate-500 uppercase">Subject Pattern</label>
                <input 
                  type="text" 
                  value={filters.subject || ''}
                  onChange={(e) => handleFilterChange('subject', e.target.value)}
                  className="mt-1 block w-full rounded-md border-slate-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm px-3 py-2 border bg-white text-slate-900"
                  placeholder="e.g. *error*"
                />
              </div>

              <div className="grid grid-cols-2 gap-2">
                  <div>
                    <label className="text-xs font-medium text-slate-500 uppercase">Priority</label>
                    <select
                      value={filters.priority}
                      onChange={(e) => handleFilterChange('priority', e.target.value)}
                      className="mt-1 block w-full rounded-md border-slate-300 shadow-sm sm:text-xs px-2 py-2 border bg-white text-slate-900"
                    >
                      <option value="">All</option>
                      <option value="P1">P1</option>
                      <option value="P2">P2</option>
                      <option value="P3">P3</option>
                      <option value="P4">P4</option>
                    </select>
                  </div>
                  <div>
                    <label className="text-xs font-medium text-slate-500 uppercase">Type</label>
                    <select
