                                <Clock className="h-3 w-3 text-slate-400" />
                                <span>{new Date(ticket.created).toLocaleDateString()}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                  );
                })}
              </div>
           </div>

           {/* Ticket Detail View */}
           {(selectedTicket) && (
             <div className="flex-[2] bg-white flex flex-col h-full overflow-hidden absolute inset-0 lg:static z-20">
