               {/* Scrollable Content */}
               <div className="flex-1 overflow-y-auto custom-scrollbar p-6 bg-slate-50/50">

                  {/* AI Analysis Card (Top of Detail View) */}
                  {aiResults[selectedTicket.ticketId] && (
                      <div className="max-w-3xl mx-auto mb-8 animate-fadeIn">
