import { GoogleGenAI, Type } from "@google/genai";
import { Ticket, TicketHistoryItem, AiAnalysisResult, GeminiModel } from '../types';

const analysisSchema: any = {
  type: Type.OBJECT,
  properties: {
    score: {
      type: Type.NUMBER,
      description: "A quality score from 1 to 10 based on handling best practices.",
    },
    summary: {
      type: Type.STRING,
      description: "A concise 1-sentence summary of the ticket handling quality.",
    },
    strengths: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of positive aspects.",
    },
    weaknesses: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of negative aspects.",
    },
    rcaDetected: {
      type: Type.BOOLEAN,
      description: "True if a Root Cause Analysis was provided or discussed by a human agent.",
    },
    timeToRespond: {
      type: Type.STRING,
      description: "Calculated duration between ticket creation and first human response (e.g. '15m', '2h', '1d').",
    },
    timeToResolve: {
      type: Type.STRING,
      description: "Calculated duration between ticket creation and resolution (e.g. '4h', '3d').",
    }
  },
  required: ["score", "summary", "strengths", "weaknesses", "rcaDetected", "timeToRespond", "timeToResolve"],
};

export class AiService {
  static getModels(): GeminiModel[] {
    return [
      { id: 'gemini-3-flash-preview', displayName: 'Gemini 3 Flash' },
      { id: 'gemini-3-pro-preview', displayName: 'Gemini 3 Pro' },
    ];
  }

  static async validateApiKey(): Promise<boolean> {
    if (!process.env.API_KEY) return false;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: 'Test connection',
      });
      return true;
    } catch (e) {
      return false;
    }
  }

  static constructPrompt(ticket: Ticket, history: TicketHistoryItem[]): string {
    const historyText = history.map(h => {
      let details = '';
      if (h.comment) {
        const textContent = h.comment.content.replace(/<[^>]*>/g, ' ');
        details = `Comment: "${textContent}"`;
      } else if (h.fieldUpdates && h.fieldUpdates.length > 0) {
        details = `Updates: ${h.fieldUpdates.map(u => `${u.field} changed from ${u.oldValue} to ${u.newValue}`).join(', ')}`;
      } else {
        details = 'System/Workflow action';
      }
      return `[${h.created}] ${h.actorName || h.actorId} (${h.source}): ${details}`;
    }).join('\n');

    return `
      You are a Professional QA Auditor for Enterprise IT Support Tickets.
      Analyze the ticket history to evaluate quality and calculate metrics.

      TICKET METADATA:
      ID: ${ticket.ticketId}
      Created: ${ticket.created}
      Subject: ${ticket.subject}
      Priority: ${ticket.priority}
      Status: ${ticket.status}
      Client: ${ticket.ticketClientName}
      Requester: ${ticket.requesterEmail}

      FULL HISTORY LOG:
      ${historyText}

      EVALUATION CRITERIA:
      1. Timeliness: 
         - Calculate 'timeToRespond': Gap between 'Created' and the first human comment/update (ignore automated bot greetings).
         - Calculate 'timeToResolve': Gap between 'Created' and when status became RESOLVED.
      2. Root Cause Analysis (RCA): 
         - Only set rcaDetected to true if a human Engineer/Agent clearly articulates the root cause.
         - IGNORE automated "rca:" tags.
      3. Quality Score: 1-10 based on depth, tone, and outcome.

      Provide a strict JSON response.
    `;
  }

  static async analyzeTicket(ticket: Ticket, history: TicketHistoryItem[], modelName: string): Promise<AiAnalysisResult> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = this.constructPrompt(ticket, history);
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
      },
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("Empty response from AI");
    const parsed = JSON.parse(jsonText);
    return { ticketId: ticket.ticketId, ...parsed };
  }
}

