                  </div>
              </div>

              <div className={filters.ticketIds ? 'opacity-30 pointer-events-none' : ''}>
                  <label className="text-xs font-medium text-slate-500 uppercase">Date Range</label>
                  <div className="grid grid-cols-2 gap-2 mt-1">
                    <input 
                        type="date"
